const QUESTIONS_CCSP_C3 = [
  { id:1401, domain:6, level:1, question:"Which of the following BEST describes the primary legal challenge of cloud computing from a jurisdictional perspective?", options:["A Cloud providers are solely responsible for legal compliance","B Cloud services are exempt from national laws","C Legal requirements only apply to on-premises data","D Data stored in multiple countries may be subject to conflicting legal requirements"], correct:3, explanation:"Cloud data may reside in multiple jurisdictions simultaneously, each with different data protection laws, government access requirements, and regulatory frameworks, creating complex compliance obligations and potential conflicts between national laws." },
  { id:1402, domain:6, level:2, question:"Which of the following international privacy regulations has had the MOST significant global impact on cloud data processing practices?", options:["A The EU General Data Protection Regulation (GDPR)","B The California Consumer Privacy Act (CCPA)","C The Health Insurance Portability and Accountability Act (HIPAA)","D The US PATRIOT Act"], correct:0, explanation:"GDPR has had the most global impact, establishing comprehensive requirements for processing EU personal data that affect organizations worldwide, setting a high baseline for data protection that has influenced privacy legislation globally." },
  { id:1403, domain:6, level:1, question:"What is the PRIMARY purpose of a Business Associate Agreement (BAA) in cloud computing contexts?", options:["A Defining the cloud provider's service level obligations","B Defining business partnership terms for joint cloud ventures","C Restricting cloud data to US data centers","D Establishing contractual HIPAA compliance obligations for cloud providers handling PHI"], correct:3, explanation:"Under HIPAA, a BAA is required with any vendor (business associate) that creates, receives, maintains, or transmits PHI on behalf of a covered entity; it establishes the provider's obligations to protect health information." },
  { id:1404, domain:6, level:2, question:"Under GDPR, which of the following roles is the cloud customer (organization controlling data collection purposes)?", options:["A Data subject","B Data processor","C Data controller","D Data steward"], correct:2, explanation:"GDPR defines the data controller as the entity that determines the purposes and means of processing personal data; cloud customers decide why and how personal data is collected and processed, making them controllers." },
  { id:1405, domain:6, level:2, question:"Which of the following BEST describes the cloud provider's role under GDPR when processing customer data on behalf of the customer?", options:["A Joint controller","B Data controller","C Sub-processor","D Data processor"], correct:3, explanation:"Cloud providers that process personal data strictly according to customer instructions (e.g., providing IaaS, PaaS, or SaaS) are typically data processors under GDPR, while customers are controllers who determine processing purposes." },
  { id:1406, domain:6, level:3, question:"A US company is using a European cloud provider to process EU customer data. The company wants to transfer this data to its US headquarters for analysis. The MOST appropriate legal mechanism is:", options:["A Encrypting the data before transfer","B Standard Contractual Clauses (SCCs) approved by the European Commission","C A formal agreement with the European cloud provider","D Requesting an exemption from GDPR requirements"], correct:1, explanation:"Standard Contractual Clauses (SCCs) are the primary legal mechanism for transferring personal data from the EU/EEA to third countries (like the US) without an adequacy decision, as approved by the European Commission." },
  { id:1407, domain:6, level:1, question:"What is the PRIMARY purpose of eDiscovery in cloud legal proceedings?", options:["A Discovering new cloud services and capabilities","B Discovering hidden security vulnerabilities in cloud systems","C Identifying, collecting, and preserving electronically stored information for legal proceedings","D Investigating cloud provider compliance with regulations"], correct:2, explanation:"eDiscovery involves the identification, preservation, collection, review, and production of electronically stored information (ESI) in response to litigation or regulatory investigations, a complex challenge in cloud environments." },
  { id:1408, domain:6, level:2, question:"Which of the following BEST describes the challenge of eDiscovery in cloud environments?", options:["A Cloud environments make eDiscovery faster and less expensive","B Cloud providers always cooperate fully with eDiscovery requests","C Data may be commingled with other customers' data, distributed across jurisdictions, and difficult to isolate","D eDiscovery only applies to on-premises systems"], correct:2, explanation:"Cloud eDiscovery is challenging because data may be stored in multi-tenant environments across multiple jurisdictions, potentially commingled with other tenants' data, requiring provider cooperation and specialized tools to isolate and collect relevant evidence." },
  { id:1409, domain:6, level:1, question:"Which of the following BEST describes the concept of a 'data processing agreement' (DPA) in cloud contracts?", options:["A An agreement for outsourcing data processing operations to third parties","B An agreement defining data processing performance benchmarks","C A contractual agreement outlining how a cloud provider processes personal data in compliance with privacy regulations","D A technical specification for cloud data processing architectures"], correct:2, explanation:"A DPA (required by GDPR Article 28) is a contract between data controller and processor specifying processing purposes, security obligations, sub-processor management, and data subject rights support obligations." },
  { id:1410, domain:6, level:3, question:"An organization receives a government request directly to their cloud provider for customer data stored in the cloud. Under GDPR, the provider should FIRST:", options:["A Notify the customer and seek to challenge the request unless legally prohibited","B Immediately provide all requested data to the government","C Refuse the request entirely","D Provide only metadata, not actual data content"], correct:0, explanation:"GDPR-compliant providers should notify customers of government access requests (unless legally prohibited by a court order) and challenge requests that are overly broad or lack proper legal basis, supporting the customer's data protection obligations." },
  { id:1411, domain:6, level:2, question:"Which of the following regulatory frameworks is MOST applicable to cloud deployments in the payment card industry?", options:["A SOX","B HIPAA","C PCI DSS","D FERPA"], correct:2, explanation:"PCI DSS (Payment Card Industry Data Security Standard) specifically governs the protection of cardholder data and applies to any organization that stores, processes, or transmits payment card data, including cloud deployments supporting payment processing." },
  { id:1412, domain:6, level:1, question:"What is the MOST important security consideration in cloud service agreements (contracts)?", options:["A The cloud provider's pricing model","B The cloud provider's customer support response times","C The geographic location of cloud data centers","D Clearly defined security responsibilities, SLAs, audit rights, and breach notification obligations"], correct:3, explanation:"Cloud contracts must clearly define shared security responsibilities, SLA commitments with remedies, the right to audit security controls, data handling requirements, and breach notification timelines to ensure accountability and compliance." },
  { id:1413, domain:6, level:2, question:"Under which condition may cloud data be subject to US government access under the CLOUD Act?", options:["A Only when data is physically stored in the United States","B Only when required by a court order issued in the jurisdiction where data is stored","C Only when authorized by the data subject","D When data is under the control of a US-based company, regardless of where it is stored"], correct:3, explanation:"The US CLOUD Act allows US law enforcement to compel US-based cloud providers to produce data under their control regardless of where the data is physically stored, creating extraterritorial access implications." },
  { id:1414, domain:6, level:1, question:"Which of the following BEST describes 'right to erasure' (right to be forgotten) under GDPR?", options:["A The right of cloud providers to delete customer data after contract termination","B Regulatory requirement to delete personal data after a maximum retention period","C Data subjects' right to have their personal data deleted under specific circumstances","D The right of organizations to permanently delete all backup data"], correct:2, explanation:"GDPR's right to erasure allows individuals to request deletion of their personal data when it is no longer necessary for its original purpose, consent is withdrawn, or other specified conditions are met." },
  { id:1415, domain:6, level:3, question:"A cloud customer discovers that their cloud provider is subject to a government data access law that conflicts with GDPR transfer restrictions. The BEST legal risk mitigation is:", options:["A Accept the legal conflict as unavoidable","B Terminate the cloud contract and migrate to a local provider","C Implement technical measures (end-to-end encryption with customer-held keys) that render data inaccessible to the provider","D Obtain legal opinions from both jurisdictions and document the risk"], correct:2, explanation:"Technical measures ensuring the provider cannot access unencrypted data (customer-managed encryption where keys are never disclosed to the provider) resolve the legal conflict by making government requests to the provider technically meaningless." },
  { id:1416, domain:6, level:2, question:"Which of the following BEST describes the concept of 'privacy impact assessment' (PIA) in cloud deployments?", options:["A A systematic analysis of how cloud deployments affect the privacy of personal data subjects","B An assessment of the financial impact of privacy breaches","C A regulatory audit of cloud provider privacy practices","D An assessment of cloud provider privacy certification compliance"], correct:0, explanation:"A PIA (or DPIA under GDPR) systematically analyzes a cloud deployment's impact on personal data privacy, identifying risks and required mitigations before deployment, required for high-risk processing activities under GDPR." },
  { id:1417, domain:6, level:1, question:"Which of the following BEST describes the purpose of cloud compliance frameworks such as FedRAMP?", options:["A Regulating cloud providers' data center locations","B Providing a standardized security assessment program for federal government cloud services","C Setting pricing standards for cloud services","D Certifying individual cloud users as competent"], correct:1, explanation:"FedRAMP (Federal Risk and Authorization Management Program) provides a standardized approach for cloud security assessment, authorization, and continuous monitoring for US federal government cloud services." },
  { id:1418, domain:6, level:2, question:"An organization using cloud services for processing personal data must appoint a Data Protection Officer (DPO) under GDPR. Which of the following BEST describes when a DPO is mandatory?", options:["A For public authorities, or organizations conducting large-scale systematic monitoring or processing of sensitive data","B For any organization with more than 250 employees","C For organizations storing more than 1 TB of personal data","D For any organization using cloud services"], correct:0, explanation:"GDPR mandates a DPO for public authorities/bodies, organizations whose core activities require large-scale systematic monitoring of individuals, or large-scale processing of special categories of data — not for all cloud users." },
  { id:1419, domain:6, level:1, question:"What is the PRIMARY purpose of a cloud provider's SOC 2 Type II report?", options:["A Providing a financial audit of cloud provider operations","B Providing independent assurance of security, availability, and confidentiality controls over a period of time","C Documenting cloud provider data center physical security controls","D Certifying cloud provider compliance with international standards"], correct:1, explanation:"SOC 2 Type II reports are produced by independent auditors and assess whether a cloud provider's security controls (Trust Service Criteria) were designed appropriately and operated effectively over an audit period, typically 6-12 months." },
  { id:1420, domain:6, level:3, question:"A healthcare organization is evaluating a cloud provider for storing PHI. The MOST important contractual requirement is:", options:["A The provider offers the lowest storage cost","B A signed Business Associate Agreement (BAA) with HIPAA-required provisions","C The provider has data centers in the United States only","D The provider offers 99.99% uptime SLA"], correct:1, explanation:"A signed BAA is a legal prerequisite for HIPAA compliance when using any vendor handling PHI; without it, the arrangement violates HIPAA regardless of technical security controls, potentially resulting in significant regulatory penalties." },
  { id:1421, domain:6, level:2, question:"Which of the following BEST describes the concept of 'cloud governance' from a legal and compliance perspective?", options:["A Technical management of cloud computing resources","B The cloud provider's internal management structure","C Government oversight of cloud computing markets","D The framework of policies, standards, and processes ensuring cloud usage complies with legal and regulatory requirements"], correct:3, explanation:"Cloud governance from a legal and compliance perspective establishes the organizational policies, standards, oversight structures, and processes that ensure cloud usage aligns with applicable laws, regulations, and contractual obligations." },
  { id:1422, domain:6, level:1, question:"Which of the following is the MOST important privacy consideration when using cloud analytics services?", options:["A The cost of cloud analytics services","B The performance of the analytics platform","C Ensuring personal data used in analytics complies with consent and purpose limitation requirements","D The geographic location of analytics processing"], correct:2, explanation:"Analytics involving personal data must align with original data collection consent and purpose limitation principles; using personal data for analytics purposes not consented to or beyond original collection purpose may violate privacy regulations." },
  { id:1423, domain:6, level:2, question:"Which of the following BEST describes the cloud risk management concept of 'risk transference'?", options:["A Moving data and workloads to a safer cloud provider","B Shifting risk to a third party through contracts, insurance, or SLAs","C Transferring responsibility for risk management to the cloud provider","D Migrating risk from one cloud region to another"], correct:1, explanation:"Risk transference involves contractually shifting financial responsibility for cloud security risks to third parties through cyber insurance, contractual SLAs with financial remedies, or other risk transfer mechanisms." },
  { id:1424, domain:6, level:3, question:"An organization is preparing to migrate regulated financial data to the cloud. The compliance team identifies that the relevant regulation requires 'right to audit.' The MOST appropriate approach is:", options:["A Select only cloud providers with physical data centers in the organization's country","B Negotiate contractual audit rights or accept third-party audit evidence as an audit substitute","C Avoid cloud services for regulated financial data","D Require the cloud provider to provide their source code for review"], correct:1, explanation:"When regulations require audit rights but direct audits of cloud infrastructure are impractical, negotiating contractual audit rights (with the right to conduct or commission audits) or accepting third-party certifications (SOC 2, ISO 27001) as substitute evidence satisfies most regulatory requirements." },
  { id:1425, domain:6, level:1, question:"Under GDPR, within how many hours must a data controller notify the supervisory authority following discovery of a personal data breach?", options:["A 7 days","B 48 hours","C 24 hours","D 72 hours"], correct:3, explanation:"GDPR Article 33 requires data controllers to notify the relevant supervisory authority within 72 hours of becoming aware of a personal data breach that is likely to result in risk to the rights and freedoms of individuals." },
  { id:1426, domain:6, level:2, question:"Which of the following BEST describes the concept of 'data minimization' as applied to cloud deployments?", options:["A Collecting and processing only the personal data necessary for specified, legitimate purposes","B Minimizing the amount of data stored in cloud environments","C Reducing cloud data storage costs through compression","D Minimizing data replication across cloud regions"], correct:0, explanation:"Data minimization is a GDPR and privacy principle requiring organizations to collect and process only the personal data that is adequate, relevant, and limited to what is necessary for the stated purpose of processing." },
  { id:1427, domain:6, level:1, question:"What is the PRIMARY purpose of a cloud exit strategy from a legal and compliance perspective?", options:["A Planning for cloud provider bankruptcy scenarios","B Maximizing financial recovery from cloud contracts","C Documenting the rationale for leaving a cloud provider","D Ensuring organized transition from a cloud provider while maintaining data protection and regulatory compliance"], correct:3, explanation:"A cloud exit strategy ensures that data can be retrieved, business continuity maintained, and regulatory obligations (data retention, deletion, portability) fulfilled during provider transitions without compliance gaps or data loss." },
  { id:1428, domain:6, level:3, question:"A cloud customer's provider experiences a significant security incident affecting the customer's data. The customer's MOST important immediate legal obligation is:", options:["A Suing the cloud provider for breach of contract","B Assessing whether the incident triggers regulatory breach notification obligations and complying with deadlines","C Terminating the cloud contract immediately","D Conducting an internal investigation before any external notifications"], correct:1, explanation:"Regulatory breach notification requirements have strict deadlines (e.g., GDPR's 72 hours); the customer must assess notification obligations as the immediate priority, as failure to notify on time creates additional regulatory liability regardless of the provider's responsibility." },
  { id:1429, domain:6, level:2, question:"Which of the following BEST describes the role of 'data portability' rights in cloud governance?", options:["A The technical ability to move data between cloud regions","B The right of individuals to receive their personal data in a machine-readable format for transfer to another controller","C Cloud contract provisions requiring data export capabilities at contract end","D Technical standards for data format compatibility between cloud providers"], correct:1, explanation:"GDPR Article 20 grants individuals the right to receive their personal data in a structured, machine-readable format and to transmit it to another controller, encouraging competition and preventing vendor lock-in with personal data." },
  { id:1430, domain:6, level:1, question:"Which of the following cloud compliance requirements MOST directly applies to US organizations handling children's online data?", options:["A COPPA","B CIPA","C FERPA","D GDPR"], correct:0, explanation:"COPPA (Children's Online Privacy Protection Act) imposes requirements on operators of websites and online services directed to children under 13, including cloud-based services, covering parental consent and data protection." },
  { id:1431, domain:6, level:2, question:"Which of the following BEST describes the purpose of an 'acceptable use policy' (AUP) for cloud services?", options:["A A policy defining which cloud services an organization may use","B Rules governing how cloud resources may be used, including prohibited activities and security requirements","C A policy governing cloud provider acceptable behavior","D Service level agreements defining cloud performance standards"], correct:1, explanation:"An AUP defines what is considered appropriate and prohibited use of cloud resources and services, protecting the organization from misuse, legal liability, and security risks arising from employees' unauthorized or harmful use of cloud services." },
  { id:1432, domain:6, level:3, question:"An organization's cloud provider contract contains a clause allowing the provider to modify security controls with 30 days' notice. From a compliance perspective, the PRIMARY risk is:", options:["A Increased cloud service costs from provider upgrades","B Changes may affect cloud service performance","C The organization may need to update its documentation","D Provider changes could reduce security controls below regulatory compliance requirements"], correct:3, explanation:"Provider discretion to modify security controls creates the risk that unilateral changes reduce controls below required compliance levels (HIPAA, PCI DSS, GDPR) without customer consent or ability to remediate, resulting in compliance violations the customer cannot prevent." },
  { id:1433, domain:6, level:1, question:"What is the PRIMARY purpose of 'legal holds' in cloud data management?", options:["A Temporarily locking cloud accounts for security reasons","B Placing legal restrictions on data access","C Suspending normal data deletion processes to preserve data relevant to pending or anticipated litigation","D Freezing cloud service contracts during disputes"], correct:2, explanation:"Legal holds suspend routine data destruction for data potentially relevant to litigation or investigation, preserving electronically stored information that would otherwise be deleted per normal retention policies, avoiding spoliation charges." },
  { id:1434, domain:6, level:2, question:"Which of the following BEST describes how ISO 27001 certification supports cloud governance?", options:["A It guarantees no security incidents will occur","B It legally exempts cloud providers from regulatory requirements","C It provides independent assurance that a provider has implemented a documented ISMS with assessed controls","D It replaces the need for contractual security requirements"], correct:2, explanation:"ISO 27001 certification demonstrates that a provider has implemented a systematic Information Security Management System that has been independently assessed and certified, providing structured assurance of security program maturity." },
  { id:1435, domain:6, level:3, question:"A cloud organization is considering using subcontractors (sub-processors) for data processing. Under GDPR, the MOST important obligation is:", options:["A Sub-processors are not allowed under GDPR","B Obtaining controller consent for sub-processors and ensuring sub-processors provide equivalent data protection guarantees","C Notifying sub-processors of applicable regulations only","D Sub-processors assume all data protection liability"], correct:1, explanation:"GDPR Article 28 requires controllers to authorize sub-processors and processors to impose equivalent data protection obligations on sub-processors by contract, maintaining the same level of protection throughout the processing chain." },
  { id:1436, domain:6, level:1, question:"Which of the following BEST describes 'data residency' requirements in cloud governance?", options:["A Legal or regulatory requirements specifying the geographic jurisdiction where data must be stored","B Requirements for backup data storage locations","C The requirement that data be stored on specific hardware","D The permanent address of cloud data center facilities"], correct:0, explanation:"Data residency requirements specify that data must be stored and processed within a defined geographic boundary (country, region), driven by national laws, regulatory requirements, or contractual obligations." },
  { id:1437, domain:6, level:2, question:"Which of the following BEST describes the risk management approach of 'accepting risk' in cloud security?", options:["A Formally acknowledging a risk and deciding not to implement additional controls based on cost-benefit analysis","B Agreeing to all cloud provider security terms without negotiation","C Assuming all cloud security risks are acceptable","D Accepting that all cloud risks are the provider's responsibility"], correct:0, explanation:"Risk acceptance is a formal management decision to acknowledge an identified risk and accept it without further mitigation because the cost of mitigation exceeds the expected loss, or the risk level is within the organization's defined risk appetite." },
  { id:1438, domain:6, level:1, question:"Which of the following is the PRIMARY reason organizations perform cloud vendor risk assessments before contracting?", options:["A To negotiate better pricing from cloud providers","B To verify the provider's technical capabilities","C To understand and manage risks posed by the cloud provider's security practices and compliance posture","D To satisfy procurement department requirements"], correct:2, explanation:"Vendor risk assessments identify security and compliance risks posed by cloud providers before contracting, enabling informed decisions, appropriate contractual protections, and risk mitigation plans for identified gaps." },
  { id:1439, domain:6, level:3, question:"A multinational organization processes EU citizen data in a US cloud. Under the current legal landscape (post-Privacy Shield invalidation), which mechanism BEST supports continued EU-US data transfers?", options:["A The EU-US Privacy Shield framework","B A bilateral government agreement between the EU and US","C Standard Contractual Clauses (SCCs) supplemented by technical measures where necessary","D Consent from each individual data subject for the transfer"], correct:2, explanation:"Following the invalidation of Privacy Shield, SCCs remain the primary mechanism for EU-US data transfers, supplemented by transfer impact assessments and technical measures (encryption with customer keys) to address the legal deficiencies identified by the CJEU." },
  { id:1440, domain:6, level:2, question:"Which of the following BEST describes the purpose of a cloud security audit?", options:["A An independent assessment of cloud security controls, configurations, and compliance","B A financial audit of cloud service expenditures","C A performance audit of cloud service delivery","D An internal review of cloud security team effectiveness"], correct:0, explanation:"A cloud security audit independently assesses whether security controls are properly designed and operating effectively, configurations meet security standards, and cloud usage complies with policies, regulations, and contractual requirements." },
  { id:1441, domain:1, level:2, question:"Which of the following BEST describes 'elasticity' as a cloud computing characteristic?", options:["A The ability of cloud systems to survive hardware failures","B The physical flexibility of cloud data center infrastructure","C The ability to automatically scale computing resources up and down based on demand","D The adaptability of cloud services to different pricing models"], correct:2, explanation:"Elasticity enables cloud resources to automatically scale out (add capacity) during demand spikes and scale in (release capacity) when demand decreases, providing cost-efficient response to variable workloads." },
  { id:1442, domain:1, level:2, question:"A cloud architect is evaluating whether to use containers or virtual machines for a microservices deployment. The PRIMARY security advantage of VMs over containers is:", options:["A VMs have better application performance","B VMs provide stronger isolation through hardware-level separation","C VMs are easier to deploy than containers","D VMs have a smaller attack surface than containers"], correct:1, explanation:"VMs use hardware-level isolation via the hypervisor, providing stronger tenant isolation than containers which share the host OS kernel; a kernel vulnerability could potentially allow container escape to the host or other containers." },
  { id:1443, domain:1, level:1, question:"Which of the following cloud deployment considerations MOST directly affects regulatory compliance for healthcare data?", options:["A Network bandwidth between cloud regions","B Geographic location of cloud data storage relative to regulatory jurisdiction","C Cloud provider pricing model","D Cloud infrastructure performance characteristics"], correct:1, explanation:"Healthcare data regulations (HIPAA in the US, GDPR in the EU) impose requirements based on geographic jurisdiction; data stored in specific countries may trigger different regulatory obligations and transfer restrictions." },
  { id:1444, domain:1, level:3, question:"An organization is evaluating cloud providers for a highly sensitive government workload. The MOST appropriate security consideration is:", options:["A The provider's customer base size","B FedRAMP authorization level and the impact level (Low, Moderate, High) matching the data classification","C Number of data centers the provider operates","D Cost of the cloud service"], correct:1, explanation:"FedRAMP defines three impact levels (Low, Moderate, High) with increasingly rigorous security controls; selecting a provider with FedRAMP authorization at the appropriate impact level ensures the security posture matches the sensitivity of government data." },
  { id:1445, domain:2, level:2, question:"Which of the following BEST describes homomorphic encryption and its cloud security application?", options:["A Encryption that can be performed at high speed in cloud environments","B Encryption allowing computation on encrypted data without decryption, protecting data in use","C A cloud provider's method for encrypting customer data","D Encryption using multiple keys for defense in depth"], correct:1, explanation:"Homomorphic encryption allows mathematical operations on ciphertext that produce encrypted results corresponding to operations on plaintext, enabling cloud analytics on sensitive data without exposing the underlying values." },
  { id:1446, domain:2, level:1, question:"Which of the following data security controls is MOST appropriate for protecting sensitive data in cloud database query results returned to applications?", options:["A Encrypting the database at rest","B Masking sensitive fields in query results based on user authorization level","C Requiring TLS for all database connections","D Implementing database activity monitoring"], correct:1, explanation:"Masking sensitive fields in query results based on user authorization (dynamic data masking) allows authorized queries while protecting sensitive values (like full credit card numbers) from users who should see only partial data." },
  { id:1447, domain:3, level:2, question:"Which of the following BEST describes the security role of an Internet Gateway in a cloud VPC?", options:["A Enabling internet-routable communication between the VPC and the public internet","B Providing private connectivity between the VPC and on-premises networks","C Acting as a firewall between the VPC and the internet","D Managing DNS resolution for VPC resources"], correct:0, explanation:"An Internet Gateway enables VPC resources to communicate with the internet (both inbound and outbound), routing internet-bound traffic from the VPC to the public internet and routing internet traffic to publicly accessible VPC resources." },
  { id:1448, domain:3, level:1, question:"Which of the following BEST describes the purpose of a cloud 'landing zone' from a security perspective?", options:["A The first cloud service deployed in an organization's environment","B The on-premises location for staging cloud migrations","C A pre-configured, secure baseline cloud environment implementing governance guardrails","D The geographic location where cloud traffic lands"], correct:2, explanation:"A cloud landing zone is a pre-configured environment with built-in security guardrails, governance policies, and baseline configurations that ensures new workloads are deployed into a consistently secure, compliant foundation." },
  { id:1449, domain:4, level:2, question:"Which of the following application security threats is MOST specific to containerized cloud applications?", options:["A SQL injection","B Insecure direct object references","C Malicious container images with embedded malware in trusted registries","D Cross-site scripting"], correct:2, explanation:"Container image supply chain attacks — malicious code embedded in base images or dependencies from registries — are a cloud-container-specific threat, particularly when organizations use unverified images from public registries without scanning." },
  { id:1450, domain:5, level:2, question:"Which of the following cloud security operations metrics BEST indicates the maturity of an organization's threat detection capability?", options:["A Number of security tools deployed","B Mean time to detect (MTTD) and percentage of threats detected vs. simulated","C Number of security analysts in the SOC","D Amount of log data collected per day"], correct:1, explanation:"MTTD and detection rate against known threat scenarios (measured through purple team exercises or red team results) directly measure detection capability effectiveness, showing how quickly and completely threats are identified." },
  { id:1451, domain:6, level:2, question:"Which of the following BEST describes the 'right to access' under GDPR?", options:["A Data subjects' right to obtain confirmation of and access to their personal data being processed","B Organizations' right to access all cloud resources","C Cloud providers' right to access customer data for operations","D Security teams' right to access all cloud logs and data"], correct:0, explanation:"GDPR Article 15 grants data subjects the right to obtain confirmation of whether their personal data is being processed and to receive a copy of that data, along with information about processing purposes, recipients, and retention periods." },
  { id:1452, domain:6, level:1, question:"Which regulatory framework applies SPECIFICALLY to payment card data security?", options:["A PCI DSS","B HIPAA","C SOX","D GLBA"], correct:0, explanation:"PCI DSS (Payment Card Industry Data Security Standard) is specifically designed to protect payment cardholder data, applying to all entities that store, process, or transmit card data regardless of their industry sector." },
  { id:1453, domain:6, level:3, question:"A cloud organization wants to demonstrate security control effectiveness to regulators without providing direct access to cloud infrastructure. The MOST appropriate evidence is:", options:["A Independent third-party audit reports (SOC 2 Type II) covering the relevant control period","B Self-prepared security questionnaire responses","C Screen recordings of security dashboard configurations","D Security architecture diagrams"], correct:0, explanation:"SOC 2 Type II reports from independent auditors provide time-period control effectiveness evidence that regulators accept as substitute for direct audit access, documenting controls operated effectively over the audit period." },
  { id:1454, domain:6, level:2, question:"Which of the following BEST describes the concept of 'cloud governance' from a risk management perspective?", options:["A The cloud provider's internal risk management practices","B The technical management of cloud computing resources","C The set of policies, procedures, and controls ensuring cloud risks are identified, assessed, and managed within the organization's risk appetite","D Government regulation of cloud computing markets"], correct:2, explanation:"Cloud governance from a risk perspective encompasses the policies, oversight structures, and processes that ensure cloud-related risks are systematically identified, assessed against the organization's risk appetite, and managed through appropriate controls." },
  { id:1455, domain:6, level:1, question:"What is the PRIMARY purpose of a Service Level Agreement (SLA) in cloud contracts from a security perspective?", options:["A Defining cloud service pricing","B Establishing measurable security and availability commitments with remedies for non-compliance","C Specifying the technical architecture of cloud services","D Defining the cloud provider's intellectual property rights"], correct:1, explanation:"From a security perspective, SLAs establish measurable commitments for availability, security incident response, breach notification timing, and recovery objectives, with defined remedies (credits, termination rights) if commitments are not met." },
  { id:1456, domain:1, level:1, question:"Which of the following BEST describes the cloud computing concept of 'as-a-service'?", options:["A Cloud services delivered only over the internet","B Computing services that cost nothing to use","C Services that are always available 24/7","D Delivery of computing capabilities as a measured, on-demand service without requiring infrastructure ownership"], correct:3, explanation:"'As-a-service' delivery means computing capabilities are delivered as utility-style services that consumers can access on-demand, pay for based on usage, and scale without acquiring or managing physical infrastructure." },
  { id:1457, domain:1, level:2, question:"Which of the following BEST describes the purpose of cloud provider regions and availability zones from a security and resilience perspective?", options:["A Reducing network latency for users in different geographic areas","B Meeting data residency requirements for all customers automatically","C Reducing cloud provider infrastructure costs through geographic optimization","D Providing geographic distribution and isolated failure domains to support high availability and disaster recovery"], correct:3, explanation:"Cloud regions provide geographic distribution for disaster recovery, while availability zones within regions provide isolated failure domains (separate power, cooling, networking) enabling high-availability architectures resilient to zone-level failures." },
  { id:1458, domain:2, level:2, question:"Which of the following BEST describes the concept of 'confidential computing'?", options:["A Hardware-based protection of data in use within trusted execution environments (TEEs)","B Using confidential cloud contracts for data security","C Encrypting data before uploading to cloud services","D Using confidential security clearances for cloud administrators"], correct:0, explanation:"Confidential computing uses hardware-based trusted execution environments (Intel SGX, AMD SEV) to protect data while it is being processed, extending encryption protection to data in use — the third state beyond data at rest and in transit." },
  { id:1459, domain:3, level:1, question:"Which of the following is the PRIMARY security benefit of using cloud-provider managed security services (e.g., managed WAF, managed SIEM)?", options:["A Eliminating all security responsibility for the customer","B Guaranteeing compliance with all regulations","C Leveraging provider expertise and scale for sophisticated security capabilities without managing the underlying infrastructure","D Reducing all cloud security costs"], correct:2, explanation:"Managed security services leverage provider expertise, threat intelligence at cloud scale, and managed infrastructure, enabling sophisticated security capabilities (ML-based detection, global threat intelligence) that would be expensive or complex for individual organizations to implement." },
  { id:1460, domain:4, level:1, question:"Which of the following BEST describes 'security by design' in cloud application development?", options:["A Building security requirements and controls into application design from the start rather than adding them later","B Designing security tools to be visually appealing","C Using design patterns approved by security architects","D Designing applications that are secure without user configuration"], correct:0, explanation:"Security by design integrates security requirements, threat modeling, and security controls into the application architecture from the earliest design phase, making security a fundamental design requirement rather than an afterthought." },
  { id:1461, domain:5, level:2, question:"Which of the following BEST describes the concept of 'threat hunting' as applied specifically to cloud environments?", options:["A Automatically detecting threats using cloud-native security tools","B Proactively searching cloud logs and telemetry for indicators of compromise that automated tools haven't detected","C Hunting for cloud security configuration vulnerabilities","D Searching for cloud provider vulnerabilities to report"], correct:1, explanation:"Cloud threat hunting proactively searches through cloud audit logs, flow logs, and security events using hypotheses based on known TTPs to find adversary activity that evaded automated detection rules and signatures." },
  { id:1462, domain:6, level:2, question:"Which of the following BEST describes the concept of 'risk quantification' in cloud security?", options:["A Measuring the quantity of cloud data at risk","B Counting the number of cloud security risks","C Expressing cloud security risks in financial or business impact terms to support investment decisions","D Calculating cloud security tool deployment costs"], correct:2, explanation:"Risk quantification translates identified cloud risks into financial or business impact terms (probability × impact = expected loss), enabling data-driven investment decisions by comparing risk reduction against control costs." },
  { id:1463, domain:6, level:1, question:"Under the GDPR's 'purpose limitation' principle, personal data collected for one purpose:", options:["A Can be used for any purpose once collected","B Must be deleted immediately after its original purpose is fulfilled","C Should not be further processed in a manner incompatible with the original collection purpose","D Can only be used by the organization that collected it"], correct:2, explanation:"GDPR's purpose limitation principle requires that personal data collected for a specific, explicit, and legitimate purpose not be further processed in ways incompatible with that original purpose without additional legal basis." },
  { id:1464, domain:1, level:3, question:"An organization is designing a multi-region cloud architecture for a global application. The MOST important security consideration for data replication between regions is:", options:["A Replication speed and performance","B Cost of cross-region data transfer","C Ensuring encryption in transit, access controls on replicated data, and compliance with data residency requirements in each region","D Load balancing configuration for multi-region routing"], correct:2, explanation:"Multi-region replication requires securing data in transit (TLS), applying consistent access controls to replicated copies, and verifying that replication destinations comply with data residency and sovereignty requirements for all data categories." },
  { id:1465, domain:2, level:1, question:"Which of the following BEST describes the security challenge of 'data blending' in cloud analytics environments?", options:["A Mixing different data formats in cloud storage","B Merging development and production data in cloud environments","C Blending multiple cloud provider services into one workflow","D Combining datasets containing sensitive data with non-sensitive data, potentially exposing sensitive information through inference"], correct:3, explanation:"Data blending — combining sensitive with non-sensitive datasets — can expose sensitive information through inference (re-identification attacks) even when direct identifiers are removed, requiring careful de-identification and anonymization controls." },
  { id:1466, domain:3, level:2, question:"Which of the following cloud security controls BEST protects against privilege escalation through cloud instance metadata?", options:["A Requiring IMDSv2 and using minimal IAM permissions for instance roles","B Blocking all access to the metadata service","C Encrypting all VM communications","D Using separate VPCs for each application tier"], correct:0, explanation:"IMDSv2's session-oriented protocol prevents SSRF-based metadata theft, while minimal IAM permissions on instance roles limit the blast radius if credentials are still compromised, together addressing the metadata service privilege escalation risk." },
  { id:1467, domain:4, level:2, question:"Which of the following BEST describes the security benefit of using API gateways in cloud architectures?", options:["A Faster API response times","B Simplifying API documentation management","C Reducing the number of APIs needed in an application","D Centralized enforcement of authentication, authorization, rate limiting, and threat protection for all API traffic"], correct:3, explanation:"API gateways provide a single enforcement point for security policies across all APIs, enabling consistent authentication, authorization, rate limiting, request validation, and WAF capabilities without duplicating these controls in each individual service." },
  { id:1468, domain:5, level:1, question:"What is the PRIMARY purpose of cloud provider status pages and security bulletins?", options:["A Marketing communications about cloud service improvements","B Announcing new cloud features and pricing changes","C Providing compliance documentation for customers","D Communicating service disruptions, security incidents, and vulnerability disclosures affecting cloud services"], correct:3, explanation:"Cloud provider status pages and security bulletins communicate service disruptions, security incidents affecting shared infrastructure, and vulnerability disclosures, enabling customers to respond appropriately to provider-side events affecting their workloads." },
  { id:1469, domain:6, level:3, question:"An organization's cloud environment is audited and auditors request access to system logs containing personal data. The MOST appropriate response under GDPR principles is:", options:["A Provide access only to logs relevant to audit scope with personal data minimized or pseudonymized where possible","B Permanently delete logs before the audit to avoid disclosure","C Refuse access as logs contain personal data","D Provide full access to all logs without restriction"], correct:0, explanation:"GDPR's data minimization and purpose limitation principles require limiting auditor access to what is necessary for audit purposes, with personal data in logs pseudonymized or minimized to the extent possible while meeting audit requirements." },
  { id:1470, domain:6, level:2, question:"Which of the following BEST describes the concept of 'cloud security assurance' provided by certification programs?", options:["A A guarantee that cloud services will never be breached","B Independent validation that cloud security controls are implemented and operating as claimed","C Insurance coverage for cloud security incidents","D A license to operate cloud services from regulatory bodies"], correct:1, explanation:"Cloud security assurance programs (ISO 27001, SOC 2, FedRAMP, CSA STAR) provide independent, third-party validation of security control implementation and effectiveness, giving customers evidence-based confidence in provider security claims." },
  { id:1471, domain:1, level:2, question:"Which of the following BEST describes the security implication of using 'spot instances' or preemptible VMs in cloud environments?", options:["A Applications must be designed to handle sudden termination, requiring careful state management and data protection","B Spot instances cannot be used for security-sensitive workloads","C Spot instances receive priority security patching from providers","D Spot instances are more secure than on-demand instances"], correct:0, explanation:"Spot/preemptible instances can be terminated with short notice, requiring applications to be stateless or handle interruption gracefully; sensitive data in memory must be protected and properly flushed before termination to prevent exposure." },
  { id:1472, domain:2, level:2, question:"Which of the following BEST describes the difference between encryption and hashing in data protection?", options:["A Both can be reversed with the appropriate key","B Encryption produces longer output than hashing","C Hashing provides stronger protection than encryption","D Encryption is reversible with a key; hashing is a one-way transformation producing a fixed-size digest"], correct:3, explanation:"Encryption transforms data reversibly using a key (allowing decryption); hashing applies a one-way function producing a fixed-length digest that cannot be reversed, making hashing appropriate for password storage and integrity verification." },
  { id:1473, domain:3, level:1, question:"Which of the following BEST describes the purpose of cloud provider 'compliance center' resources?", options:["A Automated compliance scanning of customer configurations","B A compliance training platform for cloud administrators","C Managing regulatory compliance on behalf of customers","D Providing documentation, third-party audit reports, and compliance guidance specific to the provider's services"], correct:3, explanation:"Cloud provider compliance centers offer documentation, third-party certifications, compliance briefs, and service-specific guidance helping customers understand how provider services support their compliance requirements." },
  { id:1474, domain:4, level:1, question:"Which of the following BEST describes the purpose of API versioning from a security perspective?", options:["A Allowing deprecated, insecure API versions to be retired while maintaining backward compatibility","B Improving API documentation quality","C Increasing API performance through optimized versions","D Managing API costs through version-based pricing"], correct:0, explanation:"API versioning enables organizations to deprecate and retire older versions with security vulnerabilities while giving consumers time to migrate, allowing security improvements without immediately breaking existing integrations." },
  { id:1475, domain:5, level:2, question:"Which of the following cloud security operations controls BEST ensures that security team access to cloud environments is auditable?", options:["A Reviewing security team activity logs quarterly","B Requiring security team members to document their cloud activities","C Using shared admin accounts for all security team members","D Assigning individual named accounts to each security team member with all actions logged"], correct:3, explanation:"Individual named accounts create an attribution trail linking every action to a specific person, enabling accountability, forensic investigation, and insider threat detection — shared accounts eliminate individual attribution and accountability." },
  { id:1476, domain:6, level:1, question:"What is the PRIMARY legal purpose of a cloud master service agreement (MSA)?", options:["A Establishing the overarching contractual framework governing the relationship between cloud customer and provider","B Specifying cloud service pricing and billing terms","C Defining the technical specifications of cloud services","D Documenting cloud provider security certifications"], correct:0, explanation:"An MSA establishes the overarching legal framework for the cloud relationship, defining rights, responsibilities, liability limitations, intellectual property, termination rights, and dispute resolution, within which specific service terms operate." },
  { id:1477, domain:1, level:2, question:"Which of the following cloud security considerations is MOST important when evaluating a cloud-managed Kubernetes service?", options:["A The number of supported Kubernetes versions","B The provider's responsibility for master node security and the customer's responsibility for worker node and workload security","C Network bandwidth between cluster nodes","D Kubernetes cluster performance benchmarks"], correct:1, explanation:"In managed Kubernetes, the provider manages the control plane (master nodes, API server, etcd), while the customer is responsible for worker node security, container configurations, RBAC policies, and workload security." },
  { id:1478, domain:3, level:2, question:"Which of the following BEST describes the security purpose of enabling 'versioning' on cloud object storage?", options:["A Tracking the history of file modifications for audit purposes only","B Protecting against accidental or malicious deletion by maintaining all object versions with recovery capability","C Improving object storage performance","D Managing object metadata across multiple versions"], correct:1, explanation:"Object versioning maintains all previous versions of objects, enabling recovery from accidental deletion, ransomware encryption, or malicious modification, providing a built-in recovery mechanism without separate backup infrastructure." },
  { id:1479, domain:4, level:3, question:"A developer has committed an API secret key to a public GitHub repository. The MOST time-critical remediation action is:", options:["A Notifying the security team","B Immediately revoking and rotating the compromised secret key","C Removing the secret from the repository history","D Auditing all repository access logs"], correct:1, explanation:"Secrets on public GitHub are discovered by automated scanners within seconds; immediately revoking the compromised key stops any ongoing unauthorized use; removing from git history is important but secondary to stopping active exploitation." },
  { id:1480, domain:5, level:1, question:"Which of the following BEST describes the purpose of a post-incident review (PIR) or lessons-learned process?", options:["A Measuring incident response team performance","B Documenting incidents for regulatory reporting","C Assigning blame for security incidents","D Systematically analyzing incidents to improve detection, response, and prevention capabilities"], correct:3, explanation:"Post-incident reviews analyze what happened, why, how it was detected and responded to, and what can be improved, driving systematic enhancement of security capabilities to prevent recurrence and improve future incident response." },
  { id:1481, domain:6, level:2, question:"Which of the following is the MOST important governance consideration when deploying cloud services in a regulated industry?", options:["A Verifying that cloud service deployment complies with applicable regulatory requirements and has required compliance certifications","B Ensuring cloud services offer the latest features","C Minimizing cloud deployment costs","D Maximizing cloud service performance"], correct:0, explanation:"Regulated industry cloud deployment must first verify regulatory compliance; deploying services that violate regulations (by missing required certifications, controls, or contractual safeguards) creates legal and financial risk that technical capabilities cannot offset." },
  { id:1482, domain:6, level:3, question:"An organization's cloud contract contains a limitation of liability clause capping the provider's liability at three months of service fees. From a risk management perspective, the MOST appropriate response is:", options:["A Accept the clause as standard industry practice","B Reduce cloud usage to minimize exposure within the liability cap","C Reject the contract and use only providers with unlimited liability","D Assess whether the financial cap is commensurate with data breach risk and negotiate higher limits or obtain cyber insurance"], correct:3, explanation:"Providers' liability caps often represent a small fraction of actual breach costs; risk managers should assess residual financial exposure, negotiate higher caps where possible, and obtain cyber insurance to address remaining financial risk." },
  { id:1483, domain:1, level:1, question:"Which of the following BEST describes the concept of 'cloud bursting' and its security implication?", options:["A Cloud infrastructure failures that disrupt service","B Cloud provider network capacity exceeding design limits","C The rapid growth of cloud services in an organization","D Temporarily using public cloud for overflow capacity, requiring consistent security policies across both environments"], correct:3, explanation:"Cloud bursting extends workloads into public cloud during peak demand; the security implication is ensuring consistent security policies, identity federation, and data protection controls apply to bursted workloads in the public cloud environment." },
  { id:1484, domain:2, level:1, question:"Which of the following BEST describes the concept of 'data classification' as a foundation for cloud data security?", options:["A Categorizing data by sensitivity and regulatory requirements to determine appropriate security controls","B Classifying cloud data for billing purposes","C Organizing data by access frequency for storage tiering","D Organizing cloud data by storage type"], correct:0, explanation:"Data classification assigns sensitivity levels to data assets based on their value, sensitivity, and regulatory requirements, enabling organizations to apply appropriate security controls proportionate to the risk associated with each data category." },
  { id:1485, domain:3, level:2, question:"Which of the following BEST describes the security risk of 'shadow cloud' services?", options:["A Cloud services deployed in geographically distant regions","B Cloud resources deployed behind the organization's security perimeter","C Unauthorized cloud services used by employees outside IT governance and security controls","D Cloud services operating in testing mode without proper documentation"], correct:2, explanation:"Shadow cloud services are deployed by employees without IT authorization, operating outside security governance, without compliance review, data classification, access controls, or security monitoring — creating unmanaged data exposure risks." },
  { id:1486, domain:4, level:2, question:"Which of the following BEST describes 'software composition analysis' (SCA) and its importance in cloud application security?", options:["A Reviewing the composition of cloud development teams","B Analyzing cloud application architecture designs","C Identifying and assessing security vulnerabilities in open-source and third-party software dependencies","D Analyzing cloud software licensing compliance"], correct:2, explanation:"SCA tools scan application dependencies (libraries, packages) to identify known vulnerabilities (CVEs), license compliance issues, and outdated components, addressing supply chain security risks in cloud applications." },
  { id:1487, domain:5, level:3, question:"A cloud security architect is designing a security operations capability that must detect advanced persistent threats (APTs) in a cloud environment. The MOST effective approach is:", options:["A Using only cloud-native security tools","B Implementing behavioral analytics combined with threat intelligence, custom detection rules aligned with ATT&CK, and regular threat hunting","C Deploying a SIEM with default rules","D Deploying the maximum number of security monitoring tools"], correct:1, explanation:"APT detection requires behavioral analytics to detect subtle TTPs, threat intelligence to contextualize activity, ATT&CK-aligned detection coverage to address known adversary techniques, and proactive threat hunting to find activity that evades automated detection." },
  { id:1488, domain:6, level:1, question:"Which of the following BEST describes the purpose of a cloud provider's transparency report?", options:["A Reporting cloud service performance and uptime statistics","B Disclosing the number and types of government and legal requests for customer data received","C Transparency about cloud service pricing and fees","D Reporting on cloud provider environmental sustainability"], correct:1, explanation:"Transparency reports disclose the volume and types of government and legal requests for customer data that cloud providers have received, helping customers understand the legal access risk landscape for their data." },
  { id:1489, domain:1, level:2, question:"Which of the following BEST describes the concept of a 'shared tenancy risk' in public cloud?", options:["A The risk of cloud costs being shared between tenants","B The risk of data being shared between cloud customers","C Security risks arising from sharing physical infrastructure with unknown other cloud customers","D Risk of service disruption affecting multiple tenants simultaneously"], correct:2, explanation:"Shared tenancy risk arises from co-locating workloads on physical infrastructure alongside unknown tenants, creating potential for side-channel attacks, hypervisor vulnerabilities, or data exposure from multi-tenant isolation failures." },
  { id:1490, domain:2, level:2, question:"An organization wants to protect sensitive data during cloud analytics processing. Which of the following emerging technologies BEST protects data while it is actively being computed on?", options:["A Confidential computing using trusted execution environments (TEEs)","B Data masking","C Database activity monitoring","D End-to-end encryption"], correct:0, explanation:"Confidential computing (Intel SGX, AMD SEV, ARM TrustZone) creates isolated, hardware-protected enclaves where data is decrypted and processed in hardware-protected memory inaccessible to even the cloud provider, extending encryption protection to data in use." },
  { id:1491, domain:3, level:1, question:"Which of the following BEST describes the concept of 'defense in depth' as applied to cloud network security?", options:["A Using the most advanced firewall technology available","B Applying multiple, layered network security controls including VPC security, security groups, NACLs, WAF, and IDS","C Defending only the most critical network segments","D Implementing deep packet inspection for all cloud traffic"], correct:1, explanation:"Defense in depth in cloud networking layers complementary controls — VPC segmentation, security groups (instance-level), NACLs (subnet-level), WAF (application-level), and IDS/IPS (traffic inspection) — so that each addresses threats the others may miss." },
  { id:1492, domain:4, level:1, question:"Which of the following BEST describes the purpose of 'security gates' in a cloud CI/CD pipeline?", options:["A Testing that security tools are deployed correctly","B Physical access controls for cloud developer workspaces","C Security team approvals required for all code deployments","D Automated security checks that block deployment of code with critical vulnerabilities"], correct:3, explanation:"Security gates are automated checks (SAST, DAST, SCA, secret scanning) integrated into CI/CD pipelines that block deployment when critical security issues are detected, preventing vulnerable code from reaching production." },
  { id:1493, domain:5, level:2, question:"Which of the following BEST describes the purpose of a 'kill chain' model in cloud security operations?", options:["A A process for permanently removing attacker access from cloud environments","B A workflow for executing incident response tasks","C A framework describing the stages of an attack to guide detection and response strategies at each stage","D A model for calculating the financial impact of security incidents"], correct:2, explanation:"The cyber kill chain (and MITRE ATT&CK) describes attack stages (reconnaissance, exploitation, lateral movement, etc.), enabling defenders to identify detection and prevention opportunities at each stage before attackers achieve their objectives." },
  { id:1494, domain:6, level:2, question:"Which of the following BEST describes the concept of 'right to restriction of processing' under GDPR?", options:["A Organizations' right to restrict how data processors use personal data","B Cloud providers' right to restrict data subject access requests","C The right of data subjects to restrict processing of their personal data under specific circumstances","D The right to delete all personal data"], correct:2, explanation:"GDPR Article 18 allows data subjects to request restriction of processing (data retained but processing limited) in specific circumstances, such as when accuracy is contested or processing is unlawful but the subject prefers restriction to erasure." },
  { id:1495, domain:1, level:3, question:"An organization is evaluating cloud migration risks for a legacy application with unknown security characteristics. The MOST appropriate risk assessment approach is:", options:["A Conduct a thorough security assessment of the application before migration, identifying and remediating critical findings","B Migrate immediately and address security issues as they arise","C Avoid migrating legacy applications to cloud","D Migrate to a private cloud first before moving to public cloud"], correct:0, explanation:"Legacy applications may have unknown vulnerabilities, hardcoded credentials, or insecure dependencies; a thorough pre-migration security assessment identifies critical risks that must be addressed before cloud exposure increases their potential impact." },
  { id:1496, domain:5, level:1, question:"Which of the following BEST describes the concept of 'security telemetry' in cloud security operations?", options:["A Remote monitoring of cloud infrastructure temperature and power","B Cloud provider data about customer usage patterns","C Metrics measuring cloud service performance","D Data collected from cloud security tools and services to provide visibility into security events and behaviors"], correct:3, explanation:"Security telemetry encompasses all data collected for security purposes — logs, events, network flows, metrics, alerts — providing the visibility needed for threat detection, investigation, and security program measurement in cloud environments." },
  { id:1497, domain:6, level:2, question:"Which of the following BEST describes the purpose of a 'cloud security policy' from a governance perspective?", options:["A Technical configuration requirements for cloud security controls","B A regulatory policy mandating cloud security practices","C A policy provided by cloud providers governing service usage","D A management-approved statement defining the organization's approach to cloud security and key security requirements"], correct:3, explanation:"A cloud security policy is a management-approved document defining the organization's security expectations, principles, and requirements for cloud usage, providing the governance framework from which cloud security standards and procedures are derived." },
  { id:1498, domain:4, level:2, question:"Which of the following BEST describes the concept of 'runtime application self-protection' (RASP)?", options:["A An application that monitors other applications for security issues","B A testing methodology for dynamic application security testing","C A cloud service protecting applications from runtime environment vulnerabilities","D Security controls embedded within an application to detect and prevent attacks in real-time during execution"], correct:3, explanation:"RASP embeds security instrumentation within the application runtime, enabling it to monitor and intercept application calls in real-time, detecting and blocking attacks (injection, path traversal, deserialization) within the application itself." },
  { id:1499, domain:5, level:3, question:"A cloud security team is building a threat model for their cloud environment. Which of the following threat modeling frameworks is MOST appropriate?", options:["A A simple risk matrix of likelihood vs. impact","B A compliance checklist for applicable regulations","C OWASP Top 10 for cloud environments","D STRIDE applied to cloud data flows, components, and trust boundaries"], correct:3, explanation:"STRIDE (Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege) applied to cloud architecture components, data flows, and trust boundaries systematically identifies relevant cloud threats and required mitigations." },
  { id:1500, domain:6, level:1, question:"Which of the following BEST describes the role of a 'cloud security officer' or equivalent in an organization?", options:["A An executive or senior role responsible for cloud security strategy, governance, and risk management","B A technical role managing cloud firewall configurations","C A compliance role ensuring cloud regulatory adherence","D A cloud provider employee responsible for customer security"], correct:0, explanation:"A cloud security officer (or cloud security architect/lead) is responsible for developing and maintaining the cloud security strategy, governance framework, and risk management program, ensuring cloud security aligns with organizational objectives and risk appetite." }
];
